/**
 * Sandbox Extension - OS-level sandboxing for pi built-in tools
 *
 * Uses @anthropic-ai/sandbox-runtime to enforce filesystem and network
 * restrictions at the OS level (sandbox-exec on macOS, bubblewrap on Linux).
 *
 * This example overrides pi's built-in tools so read/write/edit/ls/find/grep
 * run in a sandboxed Node subprocess, and bash/user_bash run as sandboxed
 * shell commands. Custom tools from other extensions cannot be generically
 * sandboxed by this extension, so they are blocked by default while the
 * sandbox is active. Set `failClosed: false` to allow non-overridden tools.
 *
 * Config files (merged, project takes precedence):
 * - ~/.pi/agent/extensions/sandbox.json (global)
 * - <cwd>/.pi/sandbox.json (project-local)
 *
 * Example .pi/sandbox.json:
 * ```json
 * {
 *   "enabled": true,
 *   "failClosed": true,
 *   "network": {
 *     "allowedDomains": ["github.com", "*.github.com"],
 *     "deniedDomains": []
 *   },
 *   "filesystem": {
 *     "denyRead": ["~/.ssh", "~/.aws"],
 *     "allowWrite": [".", "/tmp"],
 *     "denyWrite": [".env"]
 *   }
 * }
 * ```
 *
 * Usage:
 * - `pi -e ./sandbox` - sandbox enabled with default/config settings
 * - `pi -e ./sandbox --no-sandbox` - disable sandboxing
 * - `/sandbox` - show current sandbox configuration
 *
 * Setup:
 * 1. Copy sandbox/ directory to ~/.pi/agent/extensions/
 * 2. Run `npm install` in ~/.pi/agent/extensions/sandbox/
 *
 * Linux also requires: bubblewrap, socat, ripgrep
 */

import { spawn } from "node:child_process";
import { existsSync, readFileSync } from "node:fs";
import { homedir } from "node:os";
import { isAbsolute, join, resolve as resolvePath } from "node:path";
import { SandboxManager, type SandboxRuntimeConfig } from "@anthropic-ai/sandbox-runtime";
import {
	type AgentToolResult,
	type BashOperations,
	CONFIG_DIR_NAME,
	createBashTool,
	createEditTool,
	createFindTool,
	createGrepTool,
	createLsTool,
	createReadTool,
	createWriteTool,
	type EditToolInput,
	type FindToolInput,
	getAgentDir,
	type GrepToolInput,
	type LsToolInput,
	type ReadToolInput,
	type WriteToolInput,
	type ExtensionAPI,
} from "@earendil-works/pi-coding-agent";

interface SandboxConfig extends SandboxRuntimeConfig {
	enabled?: boolean;
	/** Block tools this extension cannot sandbox, and block all tools if sandbox initialization fails. */
	failClosed?: boolean;
}

type SubprocessBuiltinToolName = "read" | "write" | "edit" | "ls" | "find" | "grep";

const SANDBOXED_TOOL_NAMES = new Set<string>(["read", "write", "edit", "ls", "find", "grep", "bash"]);
const PI_CODING_AGENT_IMPORT_URL = import.meta.resolve("@earendil-works/pi-coding-agent");
const BUILTIN_TOOL_RUNNER_SCRIPT = `
import {
  createEditTool,
  createFindTool,
  createGrepTool,
  createLsTool,
  createReadTool,
  createWriteTool,
} from ${JSON.stringify(PI_CODING_AGENT_IMPORT_URL)};

function errorMessage(error) {
  return error instanceof Error ? error.message : String(error);
}

try {
  const chunks = [];
  for await (const chunk of process.stdin) {
    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
  }
  const request = JSON.parse(Buffer.concat(chunks).toString("utf8"));
  const factories = {
    read: createReadTool,
    write: createWriteTool,
    edit: createEditTool,
    ls: createLsTool,
    find: createFindTool,
    grep: createGrepTool,
  };
  const factory = factories[request.toolName];
  if (!factory) throw new Error(\`Unsupported sandboxed tool: \${request.toolName}\`);
  const tool = factory(request.cwd);
  const result = await tool.execute(request.toolCallId, request.params);
  process.stdout.write(JSON.stringify({ ok: true, result }));
} catch (error) {
  process.stdout.write(JSON.stringify({ ok: false, error: errorMessage(error) }));
  process.exitCode = 1;
}
`;

const DEFAULT_CONFIG: SandboxConfig = {
	enabled: true,
	failClosed: true,
	network: {
		allowedDomains: [
			"npmjs.org",
			"*.npmjs.org",
			"registry.npmjs.org",
			"registry.yarnpkg.com",
			"pypi.org",
			"*.pypi.org",
			"github.com",
			"*.github.com",
			"api.github.com",
			"raw.githubusercontent.com",
		],
		deniedDomains: [],
	},
	filesystem: {
		denyRead: ["~/.ssh", "~/.aws", "~/.gnupg"],
		allowWrite: [".", "/tmp"],
		denyWrite: [".env", ".env.*", "*.pem", "*.key"],
	},
};

interface SandboxedCommandOptions {
	input?: string | Buffer;
	onData?: (data: Buffer) => void;
	signal?: AbortSignal;
	timeout?: number;
	env?: NodeJS.ProcessEnv;
}

interface SandboxedCommandResult {
	stdout: Buffer;
	stderr: Buffer;
	exitCode: number | null;
}

interface ToolRunnerResponse {
	ok: boolean;
	result?: AgentToolResult;
	error?: string;
}

interface BuiltinToolRequest {
	toolName: SubprocessBuiltinToolName;
	cwd: string;
	toolCallId: string;
	params: unknown;
}

const sandboxedMutationQueues = new Map<string, Promise<void>>();

function loadConfig(cwd: string): SandboxConfig {
	const projectConfigPath = join(cwd, CONFIG_DIR_NAME, "sandbox.json");
	const globalConfigPath = join(getAgentDir(), "extensions", "sandbox.json");

	let globalConfig: Partial<SandboxConfig> = {};
	let projectConfig: Partial<SandboxConfig> = {};

	if (existsSync(globalConfigPath)) {
		try {
			globalConfig = JSON.parse(readFileSync(globalConfigPath, "utf-8")) as Partial<SandboxConfig>;
		} catch (e) {
			console.error(`Warning: Could not parse ${globalConfigPath}: ${e}`);
		}
	}

	if (existsSync(projectConfigPath)) {
		try {
			projectConfig = JSON.parse(readFileSync(projectConfigPath, "utf-8")) as Partial<SandboxConfig>;
		} catch (e) {
			console.error(`Warning: Could not parse ${projectConfigPath}: ${e}`);
		}
	}

	return deepMerge(deepMerge(DEFAULT_CONFIG, globalConfig), projectConfig);
}

function deepMerge(base: SandboxConfig, overrides: Partial<SandboxConfig>): SandboxConfig {
	const result: SandboxConfig = { ...base };

	if (overrides.enabled !== undefined) result.enabled = overrides.enabled;
	if (overrides.failClosed !== undefined) result.failClosed = overrides.failClosed;
	if (overrides.network) {
		result.network = { ...base.network, ...overrides.network };
	}
	if (overrides.filesystem) {
		result.filesystem = { ...base.filesystem, ...overrides.filesystem };
	}
	if (overrides.ignoreViolations) result.ignoreViolations = overrides.ignoreViolations;
	if (overrides.enableWeakerNestedSandbox !== undefined) {
		result.enableWeakerNestedSandbox = overrides.enableWeakerNestedSandbox;
	}
	if (overrides.ripgrep) result.ripgrep = overrides.ripgrep;
	if (overrides.mandatoryDenySearchDepth !== undefined) {
		result.mandatoryDenySearchDepth = overrides.mandatoryDenySearchDepth;
	}
	if (overrides.allowPty !== undefined) result.allowPty = overrides.allowPty;
	if (overrides.seccomp) result.seccomp = overrides.seccomp;

	return result;
}

function shellQuote(value: string): string {
	return `'${value.replace(/'/g, `'\\''`)}'`;
}

function sandboxedNodeCommand(script: string): string {
	return [process.execPath, "--input-type=module", "-e", script].map(shellQuote).join(" ");
}

function killProcessGroup(pid: number): void {
	try {
		process.kill(-pid, "SIGKILL");
	} catch {
		try {
			process.kill(pid, "SIGKILL");
		} catch {
			// Already gone.
		}
	}
}

async function runSandboxedCommand(
	command: string,
	cwd: string,
	options: SandboxedCommandOptions = {},
): Promise<SandboxedCommandResult> {
	if (!existsSync(cwd)) {
		throw new Error(`Working directory does not exist: ${cwd}`);
	}
	if (options.signal?.aborted) throw new Error("aborted");

	const wrappedCommand = await SandboxManager.wrapWithSandbox(command);

	return new Promise((resolve, reject) => {
		const child = spawn("bash", ["-c", wrappedCommand], {
			cwd,
			detached: process.platform !== "win32",
			env: options.env ?? process.env,
			stdio: ["pipe", "pipe", "pipe"],
		});

		let timedOut = false;
		let settled = false;
		let timeoutHandle: NodeJS.Timeout | undefined;
		const stdoutChunks: Buffer[] = [];
		const stderrChunks: Buffer[] = [];

		const settle = (fn: () => void): void => {
			if (settled) return;
			settled = true;
			if (timeoutHandle) clearTimeout(timeoutHandle);
			options.signal?.removeEventListener("abort", onAbort);
			fn();
		};

		const onAbort = (): void => {
			if (child.pid) killProcessGroup(child.pid);
		};

		if (options.timeout !== undefined && options.timeout > 0) {
			timeoutHandle = setTimeout(() => {
				timedOut = true;
				if (child.pid) killProcessGroup(child.pid);
			}, options.timeout * 1000);
		}

		options.signal?.addEventListener("abort", onAbort, { once: true });
		child.stdin?.on("error", () => {});
		child.stdin?.end(options.input);

		child.stdout?.on("data", (chunk: Buffer) => {
			stdoutChunks.push(chunk);
			options.onData?.(chunk);
		});
		child.stderr?.on("data", (chunk: Buffer) => {
			stderrChunks.push(chunk);
			options.onData?.(chunk);
		});

		child.on("error", (err) => {
			settle(() => reject(err));
		});

		child.on("close", (code) => {
			settle(() => {
				if (options.signal?.aborted) {
					reject(new Error("aborted"));
				} else if (timedOut) {
					reject(new Error(`timeout:${options.timeout}`));
				} else {
					resolve({
						stdout: Buffer.concat(stdoutChunks),
						stderr: Buffer.concat(stderrChunks),
						exitCode: code,
					});
				}
			});
		});
	});
}

function isRecord(value: unknown): value is Record<string, unknown> {
	return typeof value === "object" && value !== null;
}

function parseToolRunnerResponse(stdout: Buffer, stderr: Buffer): ToolRunnerResponse {
	const text = stdout.toString("utf8").trim();
	const stderrText = stderr.toString("utf8").trim();
	if (!text) {
		throw new Error(stderrText || "Sandboxed tool produced no response");
	}

	let parsed: unknown;
	try {
		parsed = JSON.parse(text);
	} catch (error) {
		const suffix = stderrText ? ` Stderr: ${stderrText}` : "";
		throw new Error(`Sandboxed tool returned invalid JSON: ${error instanceof Error ? error.message : error}.${suffix}`);
	}

	if (!isRecord(parsed) || typeof parsed.ok !== "boolean") {
		throw new Error("Sandboxed tool returned an invalid response shape");
	}

	return {
		ok: parsed.ok,
		result: isRecord(parsed.result) ? (parsed.result as AgentToolResult) : undefined,
		error: typeof parsed.error === "string" ? parsed.error : undefined,
	};
}

async function runSandboxedBuiltinTool(
	toolName: SubprocessBuiltinToolName,
	cwd: string,
	toolCallId: string,
	params: unknown,
	signal?: AbortSignal,
): Promise<AgentToolResult> {
	const request: BuiltinToolRequest = { toolName, cwd, toolCallId, params };
	const result = await runSandboxedCommand(sandboxedNodeCommand(BUILTIN_TOOL_RUNNER_SCRIPT), cwd, {
		input: JSON.stringify(request),
		signal,
	});
	const response = parseToolRunnerResponse(result.stdout, result.stderr);
	if (!response.ok) {
		throw new Error(response.error ?? `${toolName} failed in sandbox`);
	}
	if (result.exitCode !== 0) {
		const stderrText = result.stderr.toString("utf8").trim();
		throw new Error(stderrText || `${toolName} sandbox subprocess exited with code ${result.exitCode}`);
	}
	if (!response.result) {
		throw new Error(`${toolName} sandbox subprocess did not return a result`);
	}
	return response.result;
}

function stripAtPrefix(value: string): string {
	return value.startsWith("@") ? value.slice(1) : value;
}

function resolveToolPath(filePath: string, cwd: string): string {
	const normalized = stripAtPrefix(filePath.trim());
	if (normalized === "~") return homedir();
	if (normalized.startsWith("~/")) return resolvePath(homedir(), normalized.slice(2));
	if (isAbsolute(normalized)) return resolvePath(normalized);
	return resolvePath(cwd, normalized);
}

async function withSandboxedMutationQueue<T>(filePath: string, fn: () => Promise<T>): Promise<T> {
	const previousQueue = sandboxedMutationQueues.get(filePath) ?? Promise.resolve();
	let releaseNext!: () => void;
	const nextQueue = new Promise<void>((resolveQueue) => {
		releaseNext = resolveQueue;
	});
	const chainedQueue = previousQueue.then(
		() => nextQueue,
		() => nextQueue,
	);
	sandboxedMutationQueues.set(filePath, chainedQueue);

	await previousQueue.catch(() => {});
	try {
		return await fn();
	} finally {
		releaseNext();
		if (sandboxedMutationQueues.get(filePath) === chainedQueue) {
			sandboxedMutationQueues.delete(filePath);
		}
	}
}

function createSandboxedBashOps(): BashOperations {
	return {
		async exec(command, cwd, { onData, signal, timeout, env }) {
			const result = await runSandboxedCommand(command, cwd, { onData, signal, timeout, env });
			return { exitCode: result.exitCode };
		},
	};
}

export default function (pi: ExtensionAPI) {
	pi.registerFlag("no-sandbox", {
		description: "Disable OS-level sandboxing for built-in tool calls",
		type: "boolean",
		default: false,
	});

	const localCwd = process.cwd();
	const localRead = createReadTool(localCwd);
	const localWrite = createWriteTool(localCwd);
	const localEdit = createEditTool(localCwd);
	const localBash = createBashTool(localCwd);
	const localLs = createLsTool(localCwd);
	const localFind = createFindTool(localCwd);
	const localGrep = createGrepTool(localCwd);

	let sandboxEnabled = false;
	let sandboxInitialized = false;
	let sandboxRequired = false;
	let failClosed = DEFAULT_CONFIG.failClosed ?? true;
	let sandboxUnavailableReason: string | undefined;

	function assertSandboxOrFallback(): boolean {
		if (sandboxEnabled && sandboxInitialized) return true;
		if (sandboxRequired && failClosed) {
			throw new Error(sandboxUnavailableReason ?? "Sandbox is not active");
		}
		return false;
	}

	pi.registerTool({
		...localRead,
		label: "read (sandboxed)",
		async execute(id, params: ReadToolInput, signal, onUpdate, ctx) {
			const cwd = ctx?.cwd ?? localCwd;
			if (!assertSandboxOrFallback()) return createReadTool(cwd).execute(id, params, signal, onUpdate, ctx);
			return (await runSandboxedBuiltinTool("read", cwd, id, params, signal)) as Awaited<
				ReturnType<typeof localRead.execute>
			>;
		},
	});

	pi.registerTool({
		...localWrite,
		label: "write (sandboxed)",
		async execute(id, params: WriteToolInput, signal, onUpdate, ctx) {
			const cwd = ctx?.cwd ?? localCwd;
			if (!assertSandboxOrFallback()) return createWriteTool(cwd).execute(id, params, signal, onUpdate, ctx);
			return withSandboxedMutationQueue(resolveToolPath(params.path, cwd), async () => {
				return (await runSandboxedBuiltinTool("write", cwd, id, params, signal)) as Awaited<
					ReturnType<typeof localWrite.execute>
				>;
			});
		},
	});

	pi.registerTool({
		...localEdit,
		label: "edit (sandboxed)",
		async execute(id, params: EditToolInput, signal, onUpdate, ctx) {
			const cwd = ctx?.cwd ?? localCwd;
			if (!assertSandboxOrFallback()) return createEditTool(cwd).execute(id, params, signal, onUpdate, ctx);
			return withSandboxedMutationQueue(resolveToolPath(params.path, cwd), async () => {
				return (await runSandboxedBuiltinTool("edit", cwd, id, params, signal)) as Awaited<
					ReturnType<typeof localEdit.execute>
				>;
			});
		},
	});

	pi.registerTool({
		...localBash,
		label: "bash (sandboxed)",
		async execute(id, params, signal, onUpdate, ctx) {
			const cwd = ctx?.cwd ?? localCwd;
			if (!assertSandboxOrFallback()) return createBashTool(cwd).execute(id, params, signal, onUpdate, ctx);
			const sandboxedBash = createBashTool(cwd, {
				operations: createSandboxedBashOps(),
			});
			return sandboxedBash.execute(id, params, signal, onUpdate, ctx);
		},
	});

	pi.registerTool({
		...localLs,
		label: "ls (sandboxed)",
		async execute(id, params: LsToolInput, signal, onUpdate, ctx) {
			const cwd = ctx?.cwd ?? localCwd;
			if (!assertSandboxOrFallback()) return createLsTool(cwd).execute(id, params, signal, onUpdate, ctx);
			return (await runSandboxedBuiltinTool("ls", cwd, id, params, signal)) as Awaited<
				ReturnType<typeof localLs.execute>
			>;
		},
	});

	pi.registerTool({
		...localFind,
		label: "find (sandboxed)",
		async execute(id, params: FindToolInput, signal, onUpdate, ctx) {
			const cwd = ctx?.cwd ?? localCwd;
			if (!assertSandboxOrFallback()) return createFindTool(cwd).execute(id, params, signal, onUpdate, ctx);
			return (await runSandboxedBuiltinTool("find", cwd, id, params, signal)) as Awaited<
				ReturnType<typeof localFind.execute>
			>;
		},
	});

	pi.registerTool({
		...localGrep,
		label: "grep (sandboxed)",
		async execute(id, params: GrepToolInput, signal, onUpdate, ctx) {
			const cwd = ctx?.cwd ?? localCwd;
			if (!assertSandboxOrFallback()) return createGrepTool(cwd).execute(id, params, signal, onUpdate, ctx);
			return (await runSandboxedBuiltinTool("grep", cwd, id, params, signal)) as Awaited<
				ReturnType<typeof localGrep.execute>
			>;
		},
	});

	pi.on("tool_call", (event) => {
		if (!failClosed) return;
		if (sandboxRequired && (!sandboxEnabled || !sandboxInitialized)) {
			return { block: true, reason: sandboxUnavailableReason ?? "Sandbox is not active" };
		}
		if (sandboxEnabled && !SANDBOXED_TOOL_NAMES.has(event.toolName)) {
			return { block: true, reason: `${event.toolName} is not sandboxed by the sandbox extension` };
		}
	});

	pi.on("user_bash", () => {
		if (sandboxEnabled && sandboxInitialized) return { operations: createSandboxedBashOps() };
		if (sandboxRequired && failClosed) {
			return {
				result: {
					output: sandboxUnavailableReason ?? "Sandbox is not active",
					exitCode: 1,
					cancelled: false,
					truncated: false,
				},
			};
		}
	});

	pi.on("session_start", async (_event, ctx) => {
		const noSandbox = pi.getFlag("no-sandbox") as boolean;
		const config = loadConfig(ctx.cwd);
		failClosed = config.failClosed ?? true;
		sandboxUnavailableReason = undefined;

		if (noSandbox) {
			sandboxRequired = false;
			sandboxEnabled = false;
			sandboxInitialized = false;
			ctx.ui.setStatus("sandbox", undefined);
			ctx.ui.notify("Sandbox disabled via --no-sandbox", "warning");
			return;
		}

		if (!config.enabled) {
			sandboxRequired = false;
			sandboxEnabled = false;
			sandboxInitialized = false;
			ctx.ui.setStatus("sandbox", undefined);
			ctx.ui.notify("Sandbox disabled via config", "info");
			return;
		}

		sandboxRequired = true;
		const platform = process.platform;
		if (platform !== "darwin" && platform !== "linux") {
			sandboxEnabled = false;
			sandboxInitialized = false;
			sandboxUnavailableReason = `Sandbox not supported on ${platform}`;
			ctx.ui.notify(
				failClosed ? `${sandboxUnavailableReason}; built-in tool calls will be blocked` : sandboxUnavailableReason,
				"warning",
			);
			return;
		}

		try {
			await SandboxManager.initialize({
				network: config.network,
				filesystem: config.filesystem,
				ignoreViolations: config.ignoreViolations,
				enableWeakerNestedSandbox: config.enableWeakerNestedSandbox,
				ripgrep: config.ripgrep,
				mandatoryDenySearchDepth: config.mandatoryDenySearchDepth,
				allowPty: config.allowPty,
				seccomp: config.seccomp,
			});

			sandboxEnabled = true;
			sandboxInitialized = true;

			const networkCount = config.network.allowedDomains.length;
			const writeCount = config.filesystem.allowWrite.length;
			ctx.ui.setStatus(
				"sandbox",
				ctx.ui.theme.fg("accent", `Sandbox: ${networkCount} domains, ${writeCount} write paths`),
			);
			ctx.ui.notify("Sandbox initialized", "info");
		} catch (err) {
			sandboxEnabled = false;
			sandboxInitialized = false;
			sandboxUnavailableReason = `Sandbox initialization failed: ${err instanceof Error ? err.message : err}`;
			ctx.ui.notify(
				failClosed ? `${sandboxUnavailableReason}; built-in tool calls will be blocked` : sandboxUnavailableReason,
				"error",
			);
		}
	});

	pi.on("session_shutdown", async (_event, ctx) => {
		if (sandboxInitialized) {
			try {
				await SandboxManager.reset();
			} catch {
				// Ignore cleanup errors.
			}
		}
		sandboxEnabled = false;
		sandboxInitialized = false;
		ctx.ui.setStatus("sandbox", undefined);
	});

	pi.registerCommand("sandbox", {
		description: "Show sandbox configuration",
		handler: async (_args, ctx) => {
			if (!sandboxEnabled) {
				ctx.ui.notify(`Sandbox is disabled${sandboxUnavailableReason ? `: ${sandboxUnavailableReason}` : ""}`, "info");
				return;
			}

			const config = loadConfig(ctx.cwd);
			const lines = [
				"Sandbox Configuration:",
				"",
				`Fail closed: ${failClosed ? "yes" : "no"}`,
				`Sandboxed built-ins: ${[...SANDBOXED_TOOL_NAMES].sort().join(", ")}`,
				"",
				"Network:",
				`  Allowed: ${config.network.allowedDomains.join(", ") || "(none)"}`,
				`  Denied: ${config.network.deniedDomains.join(", ") || "(none)"}`,
				"",
				"Filesystem:",
				`  Deny Read: ${config.filesystem.denyRead.join(", ") || "(none)"}`,
				`  Allow Write: ${config.filesystem.allowWrite.join(", ") || "(none)"}`,
				`  Deny Write: ${config.filesystem.denyWrite.join(", ") || "(none)"}`,
			];
			ctx.ui.notify(lines.join("\n"), "info");
		},
	});
}

/**
 * Gondolin Tool Routing Example
 *
 * Runs pi's built-in tools inside a local Gondolin micro-VM. The host working
 * directory is mounted at /workspace in the guest. File changes under
 * /workspace write through to the host; other guest filesystem changes are
 * isolated to the VM.
 *
 * Setup:
 *   cd packages/coding-agent/examples/extensions/gondolin
 *   npm install --ignore-scripts
 *
 * Usage:
 *   cd /path/to/project
 *   pi -e /path/to/pi/packages/coding-agent/examples/extensions/gondolin
 *
 * Requirements:
 *   - Node.js >= 23.6.0 for @earendil-works/gondolin
 *   - QEMU installed (for example, `brew install qemu` on macOS)
 */

import path from "node:path";
import { RealFSProvider, VM } from "@earendil-works/gondolin";
import type { ExtensionAPI, ExtensionContext } from "@earendil-works/pi-coding-agent";
import {
	type BashOperations,
	createBashTool,
	createEditTool,
	createFindTool,
	createGrepTool,
	createLsTool,
	createReadTool,
	createWriteTool,
	DEFAULT_MAX_BYTES,
	type EditOperations,
	type FindOperations,
	formatSize,
	type GrepToolDetails,
	type GrepToolInput,
	type LsOperations,
	type ReadOperations,
	truncateHead,
	truncateLine,
	type WriteOperations,
} from "@earendil-works/pi-coding-agent";

const GUEST_WORKSPACE = "/workspace";
const DEFAULT_GREP_LIMIT = 100;

type TextToolResult<TDetails> = {
	content: Array<{ type: "text"; text: string }>;
	details: TDetails | undefined;
};

function stripAtPrefix(value: string): string {
	return value.startsWith("@") ? value.slice(1) : value;
}

function toPosix(value: string): string {
	return value.split(path.sep).join(path.posix.sep);
}

function isInsideHostPath(root: string, value: string): boolean {
	const relativePath = path.relative(root, value);
	return relativePath === "" || (!relativePath.startsWith("..") && !path.isAbsolute(relativePath));
}

function hostPathToGuest(localCwd: string, hostPath: string): string {
	const relativePath = path.relative(localCwd, hostPath);
	if (!isInsideHostPath(localCwd, hostPath)) return toPosix(hostPath);
	return relativePath ? path.posix.join(GUEST_WORKSPACE, toPosix(relativePath)) : GUEST_WORKSPACE;
}

function toGuestPath(localCwd: string, inputPath: string): string {
	const trimmed = stripAtPrefix(inputPath.trim());
	if (!trimmed) return GUEST_WORKSPACE;
	if (path.isAbsolute(trimmed)) {
		if (isInsideHostPath(localCwd, trimmed)) return hostPathToGuest(localCwd, trimmed);
		return path.posix.resolve("/", toPosix(trimmed));
	}
	return path.posix.resolve(GUEST_WORKSPACE, toPosix(trimmed));
}

function createGondolinReadOps(vm: VM, localCwd: string): ReadOperations {
	return {
		readFile: async (filePath) => vm.fs.readFile(toGuestPath(localCwd, filePath)),
		access: async (filePath) => {
			await vm.fs.access(toGuestPath(localCwd, filePath));
		},
		detectImageMimeType: async (filePath) => {
			const ext = path.posix.extname(toGuestPath(localCwd, filePath)).toLowerCase();
			if (ext === ".png") return "image/png";
			if (ext === ".jpg" || ext === ".jpeg") return "image/jpeg";
			if (ext === ".gif") return "image/gif";
			if (ext === ".webp") return "image/webp";
			return null;
		},
	};
}

function createGondolinWriteOps(vm: VM, localCwd: string): WriteOperations {
	return {
		writeFile: async (filePath, content) => {
			await vm.fs.writeFile(toGuestPath(localCwd, filePath), content, { encoding: "utf8" });
		},
		mkdir: async (dirPath) => {
			await vm.fs.mkdir(toGuestPath(localCwd, dirPath), { recursive: true });
		},
	};
}

function createGondolinEditOps(vm: VM, localCwd: string): EditOperations {
	const readOps = createGondolinReadOps(vm, localCwd);
	const writeOps = createGondolinWriteOps(vm, localCwd);
	return {
		readFile: readOps.readFile,
		writeFile: writeOps.writeFile,
		access: readOps.access,
	};
}

function createGondolinLsOps(vm: VM, localCwd: string): LsOperations {
	return {
		exists: async (filePath) => {
			try {
				await vm.fs.access(toGuestPath(localCwd, filePath));
				return true;
			} catch {
				return false;
			}
		},
		stat: async (filePath) => vm.fs.stat(toGuestPath(localCwd, filePath)),
		readdir: async (dirPath) => vm.fs.listDir(toGuestPath(localCwd, dirPath)),
	};
}

async function walkGuestFiles(
	vm: VM,
	root: string,
	visit: (guestPath: string, relativePath: string) => Promise<boolean>,
	signal?: AbortSignal,
): Promise<boolean> {
	if (signal?.aborted) throw new Error("Operation aborted");
	const stat = await vm.fs.stat(root, { signal });
	if (!stat.isDirectory()) return visit(root, path.posix.basename(root));

	const walkDirectory = async (dir: string, relativeDir: string): Promise<boolean> => {
		if (signal?.aborted) throw new Error("Operation aborted");
		const entries = await vm.fs.listDir(dir, { signal });
		for (const entry of entries) {
			if (entry === ".git" || entry === "node_modules") continue;
			const guestPath = path.posix.join(dir, entry);
			const relativePath = relativeDir ? path.posix.join(relativeDir, entry) : entry;
			let entryStat: Awaited<ReturnType<VM["fs"]["stat"]>>;
			try {
				entryStat = await vm.fs.stat(guestPath, { signal });
			} catch {
				continue;
			}
			if (entryStat.isDirectory()) {
				if (!(await walkDirectory(guestPath, relativePath))) return false;
			} else if (!(await visit(guestPath, relativePath))) {
				return false;
			}
		}
		return true;
	};

	return walkDirectory(root, "");
}

function matchesToolGlob(relativePath: string, pattern: string): boolean {
	const normalizedPattern = toPosix(pattern);
	if (normalizedPattern.includes("/")) {
		return (
			path.posix.matchesGlob(relativePath, normalizedPattern) ||
			path.posix.matchesGlob(relativePath, `**/${normalizedPattern}`)
		);
	}
	return path.posix.matchesGlob(path.posix.basename(relativePath), normalizedPattern);
}

function createGondolinFindOps(vm: VM, localCwd: string): FindOperations {
	return {
		exists: async (filePath) => {
			try {
				await vm.fs.access(toGuestPath(localCwd, filePath));
				return true;
			} catch {
				return false;
			}
		},
		glob: async (pattern, cwd, options) => {
			const root = toGuestPath(localCwd, cwd);
			const results: string[] = [];
			await walkGuestFiles(vm, root, async (guestPath, relativePath) => {
				if (results.length >= options.limit) return false;
				if (matchesToolGlob(relativePath, pattern)) results.push(guestPath);
				return results.length < options.limit;
			});
			return results;
		},
	};
}

function createLineMatcher(pattern: string, literal: boolean | undefined, ignoreCase: boolean | undefined) {
	if (literal) {
		const needle = ignoreCase ? pattern.toLowerCase() : pattern;
		return (line: string) => (ignoreCase ? line.toLowerCase() : line).includes(needle);
	}
	const regex = new RegExp(pattern, ignoreCase ? "i" : undefined);
	return (line: string) => regex.test(line);
}

function appendGrepBlock(params: {
	outputLines: string[];
	lines: string[];
	relativePath: string;
	lineIndex: number;
	contextLines: number;
}): boolean {
	let linesTruncated = false;
	const start = params.contextLines > 0 ? Math.max(0, params.lineIndex - params.contextLines) : params.lineIndex;
	const end =
		params.contextLines > 0
			? Math.min(params.lines.length - 1, params.lineIndex + params.contextLines)
			: params.lineIndex;

	for (let index = start; index <= end; index++) {
		const rawLine = params.lines[index] ?? "";
		const { text, wasTruncated } = truncateLine(rawLine.replace(/\r/g, ""));
		if (wasTruncated) linesTruncated = true;
		const separator = index === params.lineIndex ? ":" : "-";
		params.outputLines.push(`${params.relativePath}${separator}${index + 1}${separator} ${text}`);
	}
	return linesTruncated;
}

async function executeGondolinGrep(
	vm: VM,
	localCwd: string,
	params: GrepToolInput,
	signal?: AbortSignal,
): Promise<TextToolResult<GrepToolDetails>> {
	const root = toGuestPath(localCwd, params.path ?? ".");
	const rootStat = await vm.fs.stat(root, { signal });
	const rootIsDirectory = rootStat.isDirectory();
	const matcher = createLineMatcher(params.pattern, params.literal, params.ignoreCase);
	const contextLines = params.context && params.context > 0 ? params.context : 0;
	const effectiveLimit = Math.max(1, params.limit ?? DEFAULT_GREP_LIMIT);
	const outputLines: string[] = [];
	const details: GrepToolDetails = {};
	let matchCount = 0;
	let matchLimitReached = false;
	let linesTruncated = false;

	await walkGuestFiles(
		vm,
		root,
		async (guestPath, relativePath) => {
			if (matchCount >= effectiveLimit) return false;
			if (params.glob && !matchesToolGlob(relativePath, params.glob)) return true;
			let content: string;
			try {
				content = await vm.fs.readFile(guestPath, { encoding: "utf8", signal });
			} catch {
				return true;
			}
			const lines = content.replace(/\r\n/g, "\n").replace(/\r/g, "\n").split("\n");
			const displayPath = rootIsDirectory ? relativePath : path.posix.basename(guestPath);
			for (let index = 0; index < lines.length; index++) {
				if (signal?.aborted) throw new Error("Operation aborted");
				if (!matcher(lines[index] ?? "")) continue;
				matchCount++;
				if (appendGrepBlock({ outputLines, lines, relativePath: displayPath, lineIndex: index, contextLines })) {
					linesTruncated = true;
				}
				if (matchCount >= effectiveLimit) {
					matchLimitReached = true;
					return false;
				}
			}
			return true;
		},
		signal,
	);

	if (matchCount === 0) return { content: [{ type: "text", text: "No matches found" }], details: undefined };

	const rawOutput = outputLines.join("\n");
	const truncation = truncateHead(rawOutput, { maxLines: Number.MAX_SAFE_INTEGER });
	const notices: string[] = [];
	let output = truncation.content;

	if (matchLimitReached) {
		details.matchLimitReached = effectiveLimit;
		notices.push(`${effectiveLimit} matches limit reached`);
	}
	if (linesTruncated) {
		details.linesTruncated = true;
		notices.push("long lines truncated");
	}
	if (truncation.truncated) {
		details.truncation = truncation;
		notices.push(`${formatSize(DEFAULT_MAX_BYTES)} limit reached`);
	}
	if (notices.length > 0) output += `\n\n[${notices.join(". ")}]`;

	return {
		content: [{ type: "text", text: output }],
		details: Object.keys(details).length > 0 ? details : undefined,
	};
}

function sanitizeEnv(env: NodeJS.ProcessEnv | undefined): Record<string, string> | undefined {
	if (!env) return undefined;
	const result: Record<string, string> = {};
	for (const [key, value] of Object.entries(env)) {
		if (typeof value === "string") result[key] = value;
	}
	return result;
}

function createGondolinBashOps(vm: VM, localCwd: string, shellPath: string): BashOperations {
	return {
		exec: async (command, cwd, { onData, signal, timeout, env }) => {
			if (signal?.aborted) throw new Error("aborted");
			const guestCwd = toGuestPath(localCwd, cwd);
			const controller = new AbortController();
			const onAbort = () => controller.abort();
			signal?.addEventListener("abort", onAbort, { once: true });

			let timedOut = false;
			const timer =
				timeout && timeout > 0
					? setTimeout(() => {
							timedOut = true;
							controller.abort();
						}, timeout * 1000)
					: undefined;

			try {
				const proc = vm.exec([shellPath, "-lc", command], {
					cwd: guestCwd,
					env: sanitizeEnv(env),
					signal: controller.signal,
					stdout: "pipe",
					stderr: "pipe",
				});
				for await (const chunk of proc.output()) onData(chunk.data);
				const result = await proc;
				return { exitCode: result.exitCode };
			} catch (error) {
				if (signal?.aborted) throw new Error("aborted");
				if (timedOut) throw new Error(`timeout:${timeout}`);
				throw error;
			} finally {
				if (timer) clearTimeout(timer);
				signal?.removeEventListener("abort", onAbort);
			}
		},
	};
}

