function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function mergeConfig(
  base: SrtSandboxConfig,
  override: Partial<SrtSandboxConfig>,
): SrtSandboxConfig {
  const out: Record<string, unknown> = { ...base };
  for (const [key, value] of Object.entries(override) as Array<
    [keyof SrtSandboxConfig, unknown]
  >) {
    if (value === undefined) continue;
    const current = out[key as string];
    if (isRecord(current) && isRecord(value))
      out[key as string] = mergeConfig(
        current as SrtSandboxConfig,
        value as Partial<SrtSandboxConfig>,
      );
    else out[key as string] = value;
  }
  return out as SrtSandboxConfig;
}

