        const sessWrite = new Set(windowsFsStampedSet?.denyWrite ?? [])
        const expand = expandWindowsFsDenyPaths
        perExecDenyRead = expand(rawRead).filter(p => !sessRead.has(p))
        perExecDenyWrite = expand(rawWrite).filter(
