content.text:
/**
 * Pi sandbox extension for default tools.
 *
 * This intentionally keeps the maintenance surface small:
 * - tool metadata/rendering/schema comes from Pi's own create*Tool factories
 * - read/write/edit/ls/find/grep execute Pi's own tool implementation in an
 *   sandboxed Node subprocess
 * - bash/user_bash use Pi's BashOperations hook with the command wrapped by Sandbox Runtime
 * - non-default tools are blocked by default while the sandbox is active
 */

import { spawn } from "node:child_process";
import { existsSync, readFileSync } from "node:fs";
import { homedir } from "node:os";
import { isAbsolute, join, resolve as resolvePath } from "node:path";
import {
  SandboxManager,
  type SandboxRuntimeConfig,
} from "@anthropic-ai/sandbox-runtime";
import {
  CONFIG_DIR_NAME,
  createBashTool,
  createEditTool,
  createFindTool,
  createGrepTool,
  createLsTool,
  createReadTool,
  createWriteTool,
  getAgentDir,
  type AgentToolResult,
  type BashOperations,
  type ExtensionAPI,
  withFileMutationQueue,
} from "@earendil-works/pi-coding-agent";

type DefaultToolName =
  | "read"
  | "write"
  | "edit"
  | "ls"
  | "find"
  | "grep"
  | "bash";
type WorkerToolName = Exclude<DefaultToolName, "bash">;

type SandboxConfig = SandboxRuntimeConfig & {
  /** Set false to disable this extension without removing it. */
  enabled?: boolean;
  /** If true, sandbox initialization failure blocks tool calls instead of falling back to host tools. */
  failClosed?: boolean;
  /** If true, block non-default/custom tools while the sandbox is active. */
  blockNonDefaultTools?: boolean;
};

const DEFAULT_TOOLS = new Set<string>([
  "read",
  "write",
  "edit",
  "ls",
  "find",
  "grep",
  "bash",
] satisfies DefaultToolName[]);
const WORKER_TOOLS = [
  "read",
  "write",
  "edit",
  "ls",
  "find",
  "grep",
] as const satisfies WorkerToolName[];

const PI_CODING_AGENT_IMPORT_URL = import.meta
  .resolve("@earendil-works/pi-coding-agent");

const BUILTIN_TOOL_RUNNER_SCRIPT = `
import {
  createEditTool,
  createFindTool,
  createGrepTool,
  createLsTool,
  createReadTool,
  createWriteTool,
} from ${JSON.stringify(PI_CODING_AGENT_IMPORT_URL)};

function errorMessage(error) {
  return error instanceof Error ? error.message : String(error);
}

try {
  const chunks = [];
  for await (const chunk of process.stdin) chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
  const request = JSON.parse(Buffer.concat(chunks).toString("utf8"));
  const factories = {
    read: createReadTool,
    write: createWriteTool,
    edit: createEditTool,
    ls: createLsTool,
    find: createFindTool,
    grep: createGrepTool,
  };
  const factory = factories[request.toolName];
  if (!factory) throw new Error(\`Unsupported sandboxed tool: \${request.toolName}\`);
  const tool = factory(request.cwd);
  const result = await tool.execute(request.toolCallId, request.params);
  process.stdout.write(JSON.stringify({ ok: true, result }));
} catch (error) {
  process.stdout.write(JSON.stringify({ ok: false, error: errorMessage(error) }));
  process.exitCode = 1;
}
`;

const DEFAULT_CONFIG: SandboxConfig = {
  enabled: true,
  failClosed: true,
  blockNonDefaultTools: true,
  network: {
    allowedDomains: [
      "github.com",
      "*.github.com",
      "api.github.com",
      "raw.githubusercontent.com",
      "npmjs.org",
      "*.npmjs.org",
      "registry.npmjs.org",
      "registry.yarnpkg.com",
      "pypi.org",
      "*.pypi.org",
    ],
    deniedDomains: [],
    strictAllowlist: true,
  },
  filesystem: {
    denyRead: ["~/.ssh", "~/.aws", "~/.gnupg"],
    allowWrite: [".", "/tmp"],
    denyWrite: [".env", ".env.*", "*.pem", "*.key"],
  },
};

interface SandboxedCommandOptions {
  input?: string | Buffer;
  onData?: (data: Buffer) => void;
  signal?: AbortSignal;
  timeout?: number;
  env?: NodeJS.ProcessEnv;
}

interface SandboxedCommandResult {
  stdout: Buffer;
  stderr: Buffer;
  exitCode: number | null;
}

interface WorkerResponse {
  ok: boolean;
  result?: AgentToolResult;
  error?: string;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function mergeConfig(
  base: SandboxConfig,
  override: Partial<SandboxConfig>,
): SandboxConfig {
  const out: Record<string, unknown> = { ...base };
  for (const [key, value] of Object.entries(override) as Array<
    [keyof SandboxConfig, unknown]

